using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public sealed class ApiTools
{
    /// <summary>
    /// Fetches the response body from an external HTTP API endpoint.
    /// </summary>
    [McpServerTool(Name = "fetch_api", Title = "Fetch API"), Description("Fetches content from an HTTP URL and returns the response body as text.")]
    public static async Task<string> FetchApiAsync(
        HttpClient httpClient,
        [Description("The absolute URL to fetch (e.g. https://api.example.com/data)")] string url,
        CancellationToken cancellationToken)
    {
        using var response = await httpClient.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

using System.ComponentModel;
using ModelContextProtocol.Protocol;
using ModelContextProtocol.Server;

namespace McpServer.Prompts;

[McpServerPromptType]
public sealed class SummarizePrompt
{
    [McpServerPrompt(Name = "summarize", Title = "Summarize Text"), Description("Generates a prompt that asks the model to summarize the provided text.")]
    public static GetPromptResult Summarize(
        [Description("The text to summarize")] string text,
        [Description("Optional maximum length hint (e.g. '2 sentences', '100 words')")] string? maxLength = null)
    {
        var instruction = maxLength is not null
            ? $"Summarize the following text in {maxLength}:"
            : "Summarize the following text concisely:";

        return new GetPromptResult
        {
            Description = "Summarize the provided text",
            Messages =
            [
                new PromptMessage
                {
                    Role = Role.User,
                    Content = new ContentBlock
                    {
                        Type = "text",
                        Text = $"{instruction}\n\n{text}",
                    },
                },
            ],
        };
    }
}

